class Solution:
    def findKthNumber(self, n: int, k: int) -> int:
        def count(cur, n):
            s, nxt = 0, cur + 1
            while cur <= n:
                s += min(n + 1, nxt) - cur
                cur *= 10; nxt *= 10
            return s
        cur = 1; k -= 1
        while k:
            cnt = count(cur, n)
            if cnt <= k: k -= cnt; cur += 1
            else: cur *= 10; k -= 1
        return cur

