class Solution {
public:
    long long count(long long cur, long long n){
        long long s=0, nxt=cur+1;
        while(cur<=n){ s+=min(n+1,nxt)-cur; cur*=10; nxt*=10; }
        return s;
    }
    int findKthNumber(int n, int k) {
        long long cur=1; k--;
        while(k){
            long long cnt=count(cur,n);
            if(cnt<=k){ k-=cnt; cur++; }
            else { cur*=10; k--; }
        }
        return cur;
    }
};

